module execute(a_i, b_i, alu_control, pc_address, alu_res_out,
     next_sel_address);
  input [31:0] a_i, b_i, pc_address;
  input [4:0] alu_control;
  output [31:0] alu_res_out, next_sel_address;
  wire [31:0] a_i, b_i, pc_address;
  wire [4:0] alu_control;
  wire [31:0] alu_res_out, next_sel_address;
  wire UNCONNECTED12, UNCONNECTED13, UNCONNECTED14;
  assign next_sel_address[0] = pc_address[0];
  assign next_sel_address[1] = pc_address[1];
  adder u_adder0(.a (pc_address), .adder_out ({next_sel_address[31:3],
       UNCONNECTED14, UNCONNECTED13, UNCONNECTED12}));
  alu u_alu0(.a_i (a_i), .b_i (b_i), .op_i (alu_control), .res_o
       (alu_res_out));
  inv0d0 g2(.I (pc_address[2]), .ZN (next_sel_address[2]));
endmodule

